#nullable enable // autogenerated  

using MVZ2.GameContent.Seeds;
using MVZ2Logic.Level;
using MVZ2.Vanilla.Properties;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Modifiers;

namespace MVZ2.GameContent.Buffs.Level
{
    // 需在 VanillaBuffNames.Level 中登记 stoneEyePickaxeCooldown，并在 buffs.xml 添加 target="level" 的同名 buff  
    [AutoBuffDefinition(VanillaBuffNames.Level.StoneEyePickaxeCooldown)]
    public class StoneEyePickaxeCooldownBuff : BuffDefinition
    {
        public StoneEyePickaxeCooldownBuff(string nsp, string name) : base(nsp, name)
        {
            // 冷却期间禁用镐子。这里复用 decrepify 错误提示；如需专属提示可新增一个 VanillaBlueprintErrors 项  
            AddModifier(new NamespaceIDModifier(LogicLevelProps.PICKAXE_DISABLE_ID, SetOperator.Set, VanillaBlueprintErrors.decrepify));
            AddModifier(new BooleanModifier(LogicLevelProps.PICKAXE_DISABLE_ICON, true));
        }
        public override void PostAdd(Buff buff)
        {
            base.PostAdd(buff);
            // 默认时长；调用方可用 SetTimeout 覆盖  
            buff.SetProperty(PROP_TIMEOUT, MAX_TIMEOUT);
        }

        // 新增：允许外部按敌人设定不同的冷却帧数  
        public static void SetTimeout(Buff buff, int value)
        {
            buff.SetProperty(PROP_TIMEOUT, value);
        }

        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            var timeout = buff.GetProperty<int>(PROP_TIMEOUT);
            timeout--;
            buff.SetProperty(PROP_TIMEOUT, timeout);
            if (timeout <= 0)
                buff.Remove();
        }
        public static readonly VanillaBuffPropertyMeta<int> PROP_TIMEOUT = new VanillaBuffPropertyMeta<int>("Timeout");
        public const int MAX_TIMEOUT = 30; // 冷却帧数
    }
}
